import React from 'react'
import styled from 'styled-components'
import { Link } from 'react-router-dom'

const PostContainer = styled.div`
    background-color: dodgerblue;
    border-radius: 10px;
    width: 30vw;
    min-width: 200px;
    div {
        padding: 10px;
        margin:0;
        padding-bottom: 0px;
    }
    img {
      width  : 100% ;
      border-radius: inherit;
    }
`

const Button = styled.button`
    background: transparent;
    border-radius: 3px;
    border: 2px solid palevioletred;
    color: palevioletred;
    margin: 0 1em;
    padding: 0.25em 1em;
`

const Post = ({ post, deletePost, user }) => {
console.log(post._id)
  return (
        <PostContainer key={post._id}>
            <div>
                <h1> { post.status_body }</h1>
                <p> { post.date } 
                {/* <span style={ post.inStock ? { color: 'green' } : { color: 'red'}}>{ post.inStock ? 'In Stock' : 'Currently Unavailable'}</span> */}
                </p>
            </div>
            <img src={post.file} alt="" />
            { 
                user?.isAdmin ? (
                    <>  
                        {/* <Button color='blue' onClick={() => deleteCoffee(coffee._id)}>Delete</Button>
                        <Button color='red' onClick={() => deleteCoffee(coffee._id)}>Delete</Button> */}
                        <Button onClick={() => deletePost(post._id)}>Delete</Button>
                    </>
                )  : null
            }

            <Link to={`/posts/${post._id}`}>View Details</Link>
        </PostContainer>
  )
}

export default Post
